(()=>{'use strict';
const $=s=>document.querySelector(s);
const T=v=>String(v??'').trim();
let installedEvents=false,observerStarted=false;
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function css(){if($('#printStoreNameEdit296Css'))return;const st=document.createElement('style');st.id='printStoreNameEdit296Css';st.textContent='#doitPrintOverlay .shopName296{display:inline-block;min-width:140px;border-bottom:1px dashed #888;outline:0;padding:0 2px}#doitPrintOverlay .shopName296:focus{background:#fffbe6}#doitPrintOverlay .storeNameEdit296{display:none!important}#doitPrintOverlay tbody td:nth-child(3) small{display:none!important}@media print{#doitPrintOverlay .shopName296{border-bottom:0!important;background:#fff!important}#doitPrintOverlay .storeNameEdit296{display:none!important}#doitPrintOverlay tbody td:nth-child(3) small{display:none!important}}';document.head.appendChild(st)}
function selectedPs(){const list=(window.DOIT_SELECTED_PS_LIST||[]).map(T).filter(Boolean);if(list.length)return[...new Set(list)].join(', ');const key=T(window.DOIT_SELECTED_PS_KEY);if(key)return key.replace(/\|\|/g,', ');const sel=T($('#psSelect')?.value);return sel}
function hideProductDetails(ov){(ov||$('#doitPrintOverlay'))?.querySelectorAll('tbody td:nth-child(3) small').forEach(x=>x.remove())}
function cleanMeta(pg){const meta=pg.querySelector('.head>div:last-child');if(!meta)return;const parts=meta.innerHTML.split(/<br\s*\/?\s*>/i).map(T).filter(Boolean);const dateLine=parts.find(x=>/^วันที่\s*:/.test(x.replace(/<[^>]+>/g,'')))||parts[0]||'';const ps=selectedPs();meta.innerHTML=esc(dateLine.replace(/<[^>]+>/g,''))+(ps?'<br>PS: '+esc(ps):'')}
function makeShopEditable(pg){pg.querySelectorAll('.storeNameEdit296').forEach(x=>x.remove());const shop=pg.querySelector('.shop');if(!shop)return;if(shop.querySelector('.shopName296'))return;const original=T(shop.textContent).replace(/^ร้าน\s*:\s*/,'')||'ไม่ระบุร้าน';shop.dataset.originalStore=original;shop.dataset.printStore=original;shop.innerHTML='ร้าน: <span class="shopName296" contenteditable="true" spellcheck="false">'+esc(original)+'</span>';const name=shop.querySelector('.shopName296');name.addEventListener('input',()=>{shop.dataset.printStore=T(name.textContent)||original});name.addEventListener('blur',()=>{if(!T(name.textContent)){name.textContent=original;shop.dataset.printStore=original}})}
function install(){const ov=$('#doitPrintOverlay');if(!ov)return;css();hideProductDetails(ov);ov.querySelectorAll('.page').forEach(pg=>{cleanMeta(pg);makeShopEditable(pg)})}
function schedule(){setTimeout(install,0);setTimeout(install,80);setTimeout(install,250);setTimeout(install,700)}
function observeOverlay(){if(observerStarted||!document.body)return;observerStarted=true;new MutationObserver(muts=>{if(muts.some(m=>[...m.addedNodes].some(n=>n?.id==='doitPrintOverlay'||n?.querySelector?.('#doitPrintOverlay'))))schedule()}).observe(document.body,{childList:true})}
function boot(){if(installedEvents)return;installedEvents=true;css();observeOverlay();schedule();document.addEventListener('doit:scopeRendered',schedule);document.addEventListener('click',e=>{if(e.target?.id==='prepPrint'||e.target?.id==='doitPrintNow'||e.target?.id==='exportCsv')setTimeout(schedule,80)},true);document.addEventListener('doit:stateChanged',schedule)}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot,{once:true});else boot();
})();